import sys

class Solution:
    def solve(self, dllValues: list[int], target: int) -> list[tuple[int, int]]:
        n = len(dllValues)
        pairs = []
        for i in range(n):
            for j in range(i + 1, n):
                if dllValues[i] + dllValues[j] == target:
                    pairs.append((dllValues[i], dllValues[j]))
        return pairs

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        dllValues = [int(next(it)) for _ in range(n)]
        target = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(dllValues, target)
    for a, b in ans:
        print(f"{a} {b}")

