#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<pair<int,int>> solve(vector<int>& dllValues, int target) {
        int n = dllValues.size();
        vector<pair<int,int>> res;
        for (int i = 0; i < n; ++i) {
            for (int j = i + 1; j < n; ++j) {
                if (dllValues[i] + dllValues[j] == target) {
                    res.emplace_back(dllValues[i], dllValues[j]);
                }
            }
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> dllValues(n);
    for (int i = 0; i < n; ++i) cin >> dllValues[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    vector<pair<int,int>> ans = sol.solve(dllValues, target);
    for (size_t i = 0; i < ans.size(); ++i) {
        cout << ans[i].first << " " << ans[i].second;
        if (i + 1 < ans.size()) cout << "\n";
    }
    return 0;
}
